css:
color-scheme: dark;
  --app-bg: #12090b;
  --app-surface: rgba(255, 140, 140, 0.03);
  --app-surface-hover: rgba(255, 140, 140, 0.05);
  --app-border: rgba(255, 160, 160, 0.07);
  --app-border-strong: rgba(255, 140, 140, 0.14);
  --app-text: #f6ecec;
  --app-text-muted: #9a8888;
  --app-accent: #e57373;
  --app-accent-soft: rgba(229, 115, 115, 0.15);
  --app-accent-border: rgba(229, 115, 115, 0.32);
  --app-accent-nav: rgba(229, 115, 115, 0.1);
  --app-elevated: #1a1012;
  --app-glow-1: rgba(229, 115, 115, 0.16);
  --app-glow-2: rgba(160, 40, 50, 0.1);
  --app-card-shadow: 0 20px 40px rgba(0, 0, 0, 0.52), inset 0 1px 0 rgba(255, 180, 180, 0.08), inset 0 -1px 0 rgba(0, 0, 0, 0.42);
  --app-sidebar-bg: radial-gradient(circle at 14% -3%, var(--app-glow-1), transparent 42%), radial-gradient(circle at 90% 106%, var(--app-glow-2), transparent 40%), var(--app-bg);
  --app-shell-bg: var(--app-sidebar-bg);
  --media-snake-1: rgba(180, 70, 70, 0.14);
  --media-snake-2: rgba(229, 115, 115, 0.58);
  --media-snake-3: rgba(255, 200, 200, 0.96);
  --media-snake-4: rgba(200, 80, 90, 0.72);
  --bg-primary: var(--app-bg);
  --bg-secondary: var(--app-elevated);
  --bg-elevated: #221416;
  --bg-glass: rgba(18, 10, 12, 0.88);
  --text-primary: var(--app-text);
  --text-secondary: var(--app-text-muted);
  --text-tertiary: rgba(154, 136, 136, 0.72);
  --accent: var(--app-accent);
  --accent-blue: var(--app-accent);
  --focus-glow: rgba(229, 115, 115, 0.24);
